document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".tag-badge");e.forEach(t=>{t.addEventListener("click",function(){const t=this.dataset.tag;filterPosts(t),e.forEach(e=>e.classList.remove("active")),this.classList.add("active")})})});function filterPosts(e){const t=document.querySelectorAll(".portfolio-item");t.forEach(t=>{if(e==="all"){t.style.display="block";return}t.classList.contains("tag-"+e)?t.style.display="block":t.style.display="none"})}